# ── Generic classes: ToolResult[T] and Page[T] ───────────────────────────────
from __future__ import annotations
from dataclasses import dataclass, field
from typing import Generic, TypeVar

T = TypeVar("T")
K = TypeVar("K")
V = TypeVar("V")


@dataclass
class ToolResult(Generic[T]):
    """Wrapper for tool call outcomes. T is the payload type."""
    ok: bool
    data: T | None = None
    error: str | None = None

    @classmethod
    def success(cls, data: T) -> ToolResult[T]:
        return cls(ok=True, data=data)

    @classmethod
    def failure(cls, error: str) -> ToolResult[T]:
        return cls(ok=False, error=error)


@dataclass
class Page(Generic[T]):
    """Paginated result for any item type."""
    items: list[T] = field(default_factory=list)
    next_cursor: str | None = None

    @property
    def has_more(self) -> bool:
        return self.next_cursor is not None


@dataclass
class Cache(Generic[K, V]):
    """Simple in-memory cache with two type parameters."""
    _store: dict[K, V] = field(default_factory=dict)

    def get(self, key: K) -> V | None:
        return self._store.get(key)

    def set(self, key: K, value: V) -> None:
        self._store[key] = value


# --- typed usage ---
search_result: ToolResult[list[str]] = ToolResult.success(["doc-1", "doc-2"])
assert search_result.ok
assert search_result.data == ["doc-1", "doc-2"]

error_result: ToolResult[list[str]] = ToolResult.failure("timeout")
assert not error_result.ok

embedding_cache: Cache[str, list[float]] = Cache()
embedding_cache.set("hello world", [0.1, 0.2, 0.3])
vec = embedding_cache.get("hello world")  # mypy: list[float] | None

# ── Protocol definitions for agent components ────────────────────────────────
from typing import Protocol, runtime_checkable
from collections.abc import Iterator


class SupportsChat(Protocol):
    """Any object with a synchronous complete() method satisfies this protocol."""
    def complete(self, messages: list[dict[str, str]]) -> str: ...


class Retriever(Protocol):
    """Structural interface for any document retrieval backend."""
    def search(self, query: str, limit: int) -> list[str]: ...


@runtime_checkable
class RunnableTool(Protocol):
    """Tools that can be discovered at runtime via isinstance()."""
    name: str
    def run(self, **kwargs: object) -> dict[str, object]: ...


@runtime_checkable
class Tracer(Protocol):
    """Observability hook — any object with these two methods is a Tracer."""
    def on_start(self, span_name: str, metadata: dict[str, object]) -> None: ...
    def on_end(self, span_name: str, result: object) -> None: ...


# --- concrete implementations that satisfy the protocols WITHOUT inheriting ---
class MockLLM:
    """Satisfies SupportsChat: has complete(messages) -> str."""
    def complete(self, messages: list[dict[str, str]]) -> str:
        return "mock response"


class VectorRetriever:
    """Satisfies Retriever: has search(query, limit) -> list[str]."""
    def __init__(self) -> None:
        self._docs = ["doc-1: Python generics", "doc-2: Protocol typing", "doc-3: TypeVar bounds"]

    def search(self, query: str, limit: int) -> list[str]:
        return self._docs[:limit]


class CalculatorTool:
    name = "calculator"
    def run(self, **kwargs: object) -> dict[str, object]:
        expr = str(kwargs.get("expression", "0"))
        return {"result": eval(expr)}  # noqa: S307 — demo only


# --- runtime protocol check ---
calc = CalculatorTool()
print(isinstance(calc, RunnableTool))   # True — runtime_checkable
print(isinstance(42, RunnableTool))     # False

# --- agent function using protocols ---
def run_rag_agent(
    client: SupportsChat,
    retriever: Retriever,
    query: str,
    top_k: int = 3,
) -> ToolResult[str]:
    try:
        docs = retriever.search(query, top_k)
        context = "\n".join(docs)
        messages = [
            {"role": "system", "content": "Use the provided context to answer."},
            {"role": "user", "content": f"Context:\n{context}\n\nQuestion: {query}"},
        ]
        answer = client.complete(messages)
        return ToolResult.success(answer)
    except Exception as exc:
        return ToolResult.failure(str(exc))


# Swap implementations without changing run_rag_agent signature:
llm = MockLLM()
retriever = VectorRetriever()
result = run_rag_agent(llm, retriever, "what is TypeVar?")
print(result.ok, result.data)

# ── Bound TypeVar + Protocol: constrained generic ────────────────────────────
from typing import Protocol, TypeVar
from dataclasses import dataclass


class HasEmbedding(Protocol):
    """Any object that can provide a float embedding vector."""
    @property
    def embedding(self) -> list[float]: ...


EmbeddableT = TypeVar("EmbeddableT", bound=HasEmbedding)


def cosine_similarity(a: list[float], b: list[float]) -> float:
    dot = sum(x * y for x, y in zip(a, b))
    mag_a = sum(x ** 2 for x in a) ** 0.5
    mag_b = sum(x ** 2 for x in b) ** 0.5
    if mag_a == 0 or mag_b == 0:
        return 0.0
    return dot / (mag_a * mag_b)


def nearest_neighbor(query: EmbeddableT, candidates: list[EmbeddableT]) -> EmbeddableT | None:
    """Return the candidate most similar to query, preserving the concrete type."""
    if not candidates:
        return None
    return max(candidates, key=lambda c: cosine_similarity(query.embedding, c.embedding))


@dataclass
class Document:
    text: str
    embedding: list[float]   # satisfies HasEmbedding


doc1 = Document("Python generics", [0.9, 0.1, 0.0])
doc2 = Document("Protocol typing", [0.1, 0.9, 0.0])
doc3 = Document("TypeVar bounds", [0.5, 0.5, 0.1])
query_doc = Document("type parameter", [0.7, 0.3, 0.0])

best = nearest_neighbor(query_doc, [doc1, doc2, doc3])
print(best.text if best else "none")   # "Python generics"

