from typing import TypeVar, Generic
from dataclasses import dataclass, field
from collections.abc import Callable

T = TypeVar("T")

@dataclass
class Page(Generic[T]):
    items: list[T] = field(default_factory=list)
    next_cursor: str | None = None

def fetch_all(
    fetch_fn: Callable[[str | None], Page[T]],
) -> list[T]:
    """Collect all pages of any item type T."""
    out: list[T] = []
    cursor: str | None = None
    while True:
        page = fetch_fn(cursor)
        out.extend(page.items)
        if not page.next_cursor:
            break
        cursor = page.next_cursor
    return out

# Usage with a mock fetch function
def mock_fetch(cursor: str | None) -> Page[str]:
    if cursor is None:
        return Page(items=["doc-1", "doc-2"], next_cursor="page2")
    return Page(items=["doc-3"], next_cursor=None)

all_docs: list[str] = fetch_all(mock_fetch)
print(all_docs)  # ['doc-1', 'doc-2', 'doc-3']

