from __future__ import annotations
from typing import Protocol, TypeVar, Generic
from dataclasses import dataclass, field

T = TypeVar("T")

@dataclass
class ToolResult(Generic[T]):
    ok: bool
    data: T | None = None
    error: str | None = None

    @classmethod
    def success(cls, data: T) -> ToolResult[T]:
        return cls(ok=True, data=data)

    @classmethod
    def failure(cls, error: str) -> ToolResult[T]:
        return cls(ok=False, error=error)


class SupportsChat(Protocol):
    def complete(self, messages: list[dict[str, str]]) -> str: ...


class Retriever(Protocol):
    def search(self, query: str, limit: int) -> list[str]: ...


class RAGAgent:
    def __init__(self, client: SupportsChat, retriever: Retriever, top_k: int = 3) -> None:
        self.client = client
        self.retriever = retriever
        self.top_k = top_k

    def run(self, question: str) -> ToolResult[str]:
        try:
            docs = self.retriever.search(question, self.top_k)
            context = "\n---\n".join(docs)
            messages = [
                {"role": "system", "content": f"Answer using this context:\n{context}"},
                {"role": "user", "content": question},
            ]
            answer = self.client.complete(messages)
            return ToolResult.success(answer)
        except Exception as exc:
            return ToolResult.failure(f"agent error: {exc}")


# --- wiring different backends without touching RAGAgent ---
class MockLLM:
    def complete(self, messages: list[dict[str, str]]) -> str:
        return "The answer is 42."

class InMemoryRetriever:
    def __init__(self, docs: list[str]) -> None:
        self._docs = docs

    def search(self, query: str, limit: int) -> list[str]:
        return self._docs[:limit]

agent = RAGAgent(
    client=MockLLM(),
    retriever=InMemoryRetriever(["TypeVar is a type parameter placeholder.", "Protocol enables structural typing."]),
)
result = agent.run("What is TypeVar?")
print(result.ok, result.data)
